long long solve(std::string s, std::vector<long long> order, long long k) {
    int n = s.length();
    std::vector<int> positions(n, 0);

    // Record the positions of the characters in the order
    for (int i = 0; i < n; ++i) {
        positions[order[i]] = i;
    }

    // Function to calculate the number of valid substrings
    auto countValidSubstrings = [](const std::string& s, const std::vector<int>& positions) -> long long {
        int n = s.length();
        long long total = 0;
        std::vector<int> starIndices;

        // Find indices of '*' characters
        for (int i = 0; i < n; ++i) {
            if (s[i] == '*') {
                starIndices.push_back(i);
            }
        }

        // Calculate the number of valid substrings
        for (int i = 0; i < starIndices.size(); ++i) {
            int star = starIndices[i];
            int left = star;
            int right = star;

            // Expand to the left
            while (left >= 0 && s[left] != '*') {
                left--;
            }
            left++;

            // Expand to the right
            while (right < n && s[right] != '*') {
                right++;
            }
            right--;

            // Calculate the number of valid substrings that include this star
            long long leftCount = star - left + 1;
            long long rightCount = right - star + 1;
            total += leftCount * rightCount;
        }

        return total;
    };

    // Binary search for the minimum time t
    long long left = 0, right = n;
    long long result = -1;

    while (left <= right) {
        long long mid = (left + right) / 2;
        std::vector<int> currentPositions(n, 0);

        // Mark the first mid positions as '*'
        for (int i = 0; i < mid; ++i) {
            currentPositions[order[i]] = 1;
        }

        // Create the modified string
        std::string modified = s;
        for (int i = 0; i < n; ++i) {
            if (currentPositions[i] == 1) {
                modified[i] = '*';
            }
        }

        // Calculate the number of valid substrings
        long long count = countValidSubstrings(modified, currentPositions);

        if (count >= k) {
            result = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    return result;
}
