    long long total = 0;

    for (int t = 0; t < n; ++t) {
        int idx = order[t];
        replaced[idx] = true;

        // Calculate the number of valid substrings after this replacement
        // We use the fact that replacing a character with '*' increases the number of valid substrings
        // by the number of substrings that include this character
        int left = idx;
        while (left >= 0 && !replaced[left]) left--;
        int right = idx;
        while (right < n && !replaced[right]) right++;

        int count = (idx - left) * (right - idx);
        total += count;

        if (total >= k) {
            return t;
        }
    }

    return -1;
}
